package com.soumyajit.gradlemc.foundation;
import java.time.Instant;import java.util.*;
/** Serializable summaries only: this type intentionally contains no live Minecraft or Forge object. */
public record InstanceSnapshot(String gradleMcVersion,String minecraftVersion,String loaderName,String loaderVersion,String javaVersion,String javaVendor,String physicalSide,Instant capturedAt,int schemaVersion,Map<String,String> installedModSummary,List<String> resourcePacks,List<String> dataPacks,Map<String,String> configSummary,Map<String,String> settings,RuntimeContext runtime,StaticFingerprint staticFingerprint,RuntimeContextFingerprint runtimeFingerprint) {
 public enum Activity { MAIN_MENU,WORLD_IDLE,EXPLORATION,WORLD_GENERATION,INTEGRATED_SERVER,DEDICATED_SERVER,UNKNOWN } public enum ShaderState { KNOWN_ENABLED,KNOWN_DISABLED,UNKNOWN }
 public record RuntimeContext(boolean activeWorld,boolean integratedServer,Optional<String> dimension,Optional<Integer> renderDistance,Optional<Integer> simulationDistance,Optional<String> graphicsMode,ShaderState shaderState,Activity activity){public RuntimeContext{dimension=dimension==null?Optional.empty():dimension;renderDistance=renderDistance==null?Optional.empty():renderDistance;simulationDistance=simulationDistance==null?Optional.empty():simulationDistance;graphicsMode=graphicsMode==null?Optional.empty():graphicsMode;shaderState=shaderState==null?ShaderState.UNKNOWN:shaderState;activity=activity==null?Activity.UNKNOWN:activity;}}
 public InstanceSnapshot {if(Evidence.blank(gradleMcVersion)||Evidence.blank(minecraftVersion)||Evidence.blank(loaderName)||Evidence.blank(javaVersion)||capturedAt==null||schemaVersion<1||staticFingerprint==null||runtimeFingerprint==null)throw new IllegalArgumentException("Required snapshot identity missing");loaderVersion=loaderVersion==null?"unknown":loaderVersion;javaVendor=javaVendor==null?"unknown":javaVendor;physicalSide=physicalSide==null?"unknown":physicalSide;installedModSummary=Evidence.boundedMap(installedModSummary,32);resourcePacks=Evidence.boundedList(resourcePacks,256);dataPacks=Evidence.boundedList(dataPacks,256);configSummary=Evidence.boundedMap(configSummary,32);settings=Evidence.boundedMap(settings,32);runtime=runtime==null?new RuntimeContext(false,false,Optional.empty(),Optional.empty(),Optional.empty(),Optional.empty(),ShaderState.UNKNOWN,Activity.UNKNOWN):runtime;}
}
